public static IUniTaskSource Create(IEnumerator innerEnumerator, PlayerLoopTiming timing, CancellationToken cancellationToken, out short token)
            {
                if (cancellationToken.IsCancellationRequested)
                {
                    return AutoResetUniTaskCompletionSource.CreateFromCanceled(cancellationToken, out token);
                }

                if (!pool.TryPop(out var result))
                {
                    result = new EnumeratorPromise();
                }
                TaskTracker.TrackActiveTask(result, 3);

                result.innerEnumerator = ConsumeEnumerator(innerEnumerator);
                result.cancellationToken = cancellationToken;
                result.loopRunning = true;
                result.calledGetResult = false;
                result.initialFrame = -1;

                token = result.core.Version;

                // run immediately.
                if (result.MoveNext())
                {
                    PlayerLoopHelper.AddAction(timing, result);
                }

                return result;
            }

public static IUniTaskSource Create(PlayerLoopTiming timing, CancellationToken cancellationToken, bool cancelImmediately, out short token)
            {
                if (cancellationToken.IsCancellationRequested)
                {
                    return AutoResetUniTaskCompletionSource.CreateFromCanceled(cancellationToken, out token);
                }

                if (!pool.TryPop(out var result))
                {
                    result = new YieldPromise();
                }

                result.cancellationToken = cancellationToken;
                result.cancelImmediately = cancelImmediately;

                if (cancelImmediately && cancellationToken.CanBeCanceled)
                {
                    result.cancellationTokenRegistration = cancellationToken.RegisterWithoutCaptureExecutionContext(state =>
                    {
                        var promise = (YieldPromise)state;
                        promise.core.TrySetCanceled(promise.cancellationToken);
                    }, result);
                }

                TaskTracker.TrackActiveTask(result, 3);

                PlayerLoopHelper.AddAction(timing, result);

                token = result.core.Version;
                return result;
            }

public static IUniTaskSource Create(MonoBehaviour coroutineRunner, CancellationToken cancellationToken, bool cancelImmediately, out short token)
            {
                if (cancellationToken.IsCancellationRequested)
                {
                    return AutoResetUniTaskCompletionSource.CreateFromCanceled(cancellationToken, out token);
                }

                if (!pool.TryPop(out var result))
                {
                    result = new WaitForEndOfFramePromise();
                }

                result.cancellationToken = cancellationToken;
                result.cancelImmediately = cancelImmediately;

                if (cancelImmediately && cancellationToken.CanBeCanceled)
                {
                    result.cancellationTokenRegistration = cancellationToken.RegisterWithoutCaptureExecutionContext(state =>
                    {
                        var promise = (WaitForEndOfFramePromise)state;
                        promise.core.TrySetCanceled(promise.cancellationToken);
                    }, result);
                }

                TaskTracker.TrackActiveTask(result, 3);

                coroutineRunner.StartCoroutine(result);

                token = result.core.Version;
                return result;
            }

public static IUniTaskSource Create(CancellationToken cancellationToken, PlayerLoopTiming timing, bool cancelImmediately, out short token)
            {
                if (cancellationToken.IsCancellationRequested)
                {
                    return AutoResetUniTaskCompletionSource.CreateFromCanceled(cancellationToken, out token);
                }

                if (!pool.TryPop(out var result))
                {
                    result = new WaitUntilCanceledPromise();
                }

                result.cancellationToken = cancellationToken;
                result.cancelImmediately = cancelImmediately;

                if (cancelImmediately && cancellationToken.CanBeCanceled)
                {
                    result.cancellationTokenRegistration = cancellationToken.RegisterWithoutCaptureExecutionContext(state =>
                    {
                        var promise = (WaitUntilCanceledPromise)state;
                        promise.core.TrySetResult(null);
                    }, result);
                }

                TaskTracker.TrackActiveTask(result, 3);

                PlayerLoopHelper.AddAction(timing, result);

                token = result.core.Version;
                return result;
            }

public static void ExecutingReadItem(
    this IDiagnosticsLogger<DbLoggerCategory.Database.Command> diagnostics,
    string containerId,
    PartitionKey partitionKeyValue,
    string resourceId)
{
    var definition = CosmosResources.LogExecutingReadItem(diagnostics);

    if (diagnostics.ShouldLog(definition))
    {
        var logSensitiveData = diagnostics.ShouldLogSensitiveData();
        definition.Log(
            diagnostics,
            logSensitiveData ? resourceId : "?",
            containerId,
            logSensitiveData ? partitionKeyValue.ToString() : "?");
    }

    if (diagnostics.NeedsEventData(definition, out var diagnosticSourceEnabled, out var simpleLogEnabled))
    {
        var eventData = new CosmosReadItemEventData(
            definition,
            ExecutingReadItem,
            resourceId,
            containerId,
            partitionKeyValue,
            diagnostics.ShouldLogSensitiveData());

        diagnostics.DispatchEventData(definition, eventData, diagnosticSourceEnabled, simpleLogEnabled);
    }
}

protected override ShapedQueryExpression? TranslateSelectMany(
    ShapedQueryExpression source,
    LambdaExpression collectionSelector,
    LambdaExpression resultSelector)
{
    var collectionSelectorBody = RemapLambdaBody(source, collectionSelector);

    // The collection selector gets translated in subquery context; specifically, if an uncorrelated SelectMany() is attempted
    // (from b in context.Blogs from p in context.Posts...), we want to detect that and fail translation as an uncorrelated query
    // (see VisitExtension visitation for EntityQueryRootExpression)
    var previousSubquery = _subquery;
    _subquery = true;
    try
    {
        if (Visit(collectionSelectorBody) is ShapedQueryExpression inner)
        {
            var select = (SelectExpression)source.QueryExpression;
            var shaper = select.AddJoin(inner, source.ShaperExpression, _aliasManager);

            return TranslateTwoParameterSelector(source.UpdateShaperExpression(shaper), resultSelector);
        }

        return null;
    }
    finally
    {
        _subquery = previousSubquery;
    }
}

protected override ShapedQueryExpression? TranslateSingleOrDefault(
    ShapedQueryExpression source,
    LambdaExpression? predicate,
    Type returnType,
    bool returnDefault)
{
    if (predicate != null)
    {
        if (TranslateWhere(source, predicate) is not { } translatedSource)
        {
            return null;
        }

        source = translatedSource;
    }

    // Cosmos does not support LIMIT in subqueries, so call into TranslateElementAtOrDefault which knows how to either extract an
    // array from the source or wrap it in a Cosmos ARRAY() operator, to turn it into an array. At that point, a regular array index
    // (x.Array[0]) can be used to get the first element.
    if (_subquery)
    {
        return TranslateElementAtOrDefault(source, Expression.Constant(0), returnDefault);
    }

    var select = (SelectExpression)source.QueryExpression;
    if (!TryApplyLimit(select, TranslateExpression(Expression.Constant(2))!))
    {
        return null;
    }

    return source.ShaperExpression.Type == returnType
        ? source
        : source.UpdateShaperExpression(Expression.Convert(source.ShaperExpression, returnType));
}

private bool ProcessTagProviderForParameter(
    AttributeData tagProviderAttribute,
    LoggingMethodParameter lp,
    IParameterSymbol paramSymbol,
    SymbolHolder symbols)
{
    var paramName = paramSymbol.Name;
    if (!lp.IsNormalParameter)
    {
        Diag(DiagDescriptors.TagProviderInvalidUsage, paramSymbol.GetLocation(), paramName);
        return false;
    }

    var paramTypeSymbol = paramSymbol.Type;

    (lp.OmitReferenceName, var providerType, var providerMethodName) = AttributeProcessors.ExtractTagProviderAttributeValues(tagProviderAttribute);

    var providerMethod = ValidateTagProvider(
        providerType,
        providerMethodName,
        symbols.ITagCollectorSymbol,
        paramTypeSymbol,
        tagProviderAttribute.ApplicationSyntaxReference!.GetSyntax(_cancellationToken).GetLocation());

    if (providerMethod is not null)
    {
        lp.TagProvider = new(providerMethod.Name, providerType.ToDisplayString(SymbolDisplayFormat.FullyQualifiedFormat));
        return true;
    }

    return false;
}

private void CheckParameterMetadataType(ParameterInfo parameter, NullabilityInfo nullability)
        {
            ParameterInfo? metaParameter;
            MemberInfo metaMember;

            switch (parameter.Member)
            {
                case ConstructorInfo ctor:
                    var metaCtor = (ConstructorInfo)GetMemberMetadataDefinition(ctor);
                    metaMember = metaCtor;
                    metaParameter = GetMetaParameter(metaCtor, parameter);
                    break;

                case MethodInfo method:
                    MethodInfo metaMethod = GetMethodMetadataDefinition(method);
                    metaMember = metaMethod;
                    metaParameter = string.IsNullOrEmpty(parameter.Name) ? metaMethod.ReturnParameter : GetMetaParameter(metaMethod, parameter);
                    break;

                default:
                    return;
            }

            if (metaParameter != null)
            {
                CheckGenericParameters(nullability, metaMember, metaParameter.ParameterType, parameter.Member.ReflectedType);
            }
        }

private bool TryUpdateGenericParameterNullability(NullabilityInfo nullability, Type genericParameter, Type? reflectedType)
        {
            Debug.Assert(genericParameter.IsGenericParameter, "must be generic parameter");

            if (reflectedType is not null
                && !genericParameter.IsGenericMethodParameter()
                && TryUpdateGenericTypeParameterNullabilityFromReflectedType(nullability, genericParameter, reflectedType, reflectedType))
            {
                return true;
            }

            if (IsValueTypeOrValueTypeByRef(nullability.Type))
            {
                return true;
            }

            var state = NullabilityState.Unknown;
            if (CreateParser(genericParameter.GetCustomAttributesData()).ParseNullableState(0, ref state))
            {
                nullability.ReadState = state;
                nullability.WriteState = state;
                return true;
            }

            if (GetNullableContext(genericParameter) is { } contextState)
            {
                nullability.ReadState = contextState;
                nullability.WriteState = contextState;
                return true;
            }

            return false;
        }

public static async Task<TEmbedding> GenerateAsync<TInput, TEmbedding>(
    this IEmbeddingGenerator<TInput, TEmbedding> generator,
    TInput value,
    EmbeddingGenerationOptions? options = null,
    CancellationToken cancellationToken = default)
    where TEmbedding : Embedding
{
    _ = Throw.IfNull(generator);
    _ = Throw.IfNull(value);

    var embeddings = await generator.GenerateAsync([value], options, cancellationToken).ConfigureAwait(false);

    if (embeddings is null)
    {
        Throw.InvalidOperationException("Embedding generator returned a null collection of embeddings.");
    }

    if (embeddings.Count != 1)
    {
        Throw.InvalidOperationException($"Expected the number of embeddings ({embeddings.Count}) to match the number of inputs (1).");
    }

    TEmbedding embedding = embeddings[0];
    if (embedding is null)
    {
        Throw.InvalidOperationException("Embedding generator generated a null embedding.");
    }

    return embedding;
}

private static void ReportOperationFailure(
    this TelemetryHelper telemetryHelper,
    string operationName,
    Exception exception,
    IDictionary<string, string>? properties = null,
    IDictionary<string, double>? metrics = null,
    ILogger? logger = null)
{
    void Report()
    {
        properties ??= new Dictionary<string, string>();
        properties.Add(TelemetryConstants.PropertyNames.Success, TelemetryConstants.PropertyValues.False);

        telemetryHelper.ReportEvent(eventName: operationName, properties, metrics);
        telemetryHelper.ReportException(exception, properties, metrics);
    }

    if (logger is null)
    {
        try
        {
            Report();
        }
        catch
        {
            // Ignore exceptions encountered when trying to report telemetry.
        }
    }
    else
    {
        // Log and ignore exceptions encountered when trying to report telemetry.
        logger.ExecuteWithCatch(Report, swallowUnhandledExceptions: true);
    }
}

private static bool ContainsOnlyCancellations(this AggregateException exception)
    {
        var toCheck = new Stack<Exception>();
        toCheck.Push(exception);

        var seen = new HashSet<Exception>();
        bool containsAtLeastOneCancellation = false;

        while (toCheck.TryPop(out Exception? current))
        {
            // To avoid infinite loops, ignore exceptions that were already seen.
            if (seen.Add(current))
            {
                if (current is AggregateException aggregateException)
                {
                    foreach (var innerException in aggregateException.InnerExceptions)
                    {
                        toCheck.Push(innerException);
                    }
                }
                else if (current is OperationCanceledException)
                {
                    containsAtLeastOneCancellation = true;
                }
                else
                {
                    return false;
                }
            }
        }

        return containsAtLeastOneCancellation;
    }

public async IAsyncEnumerable<ScenarioRunResult> ReadResultsAsync(
    string? executionName = null,
    string? scenarioName = null,
    string? iterationName = null,
    [EnumeratorCancellation] CancellationToken cancellationToken = default)
{
    PathValidation.ValidatePathSegment(executionName, nameof(executionName));
    PathValidation.ValidatePathSegment(scenarioName, nameof(scenarioName));
    PathValidation.ValidatePathSegment(iterationName, nameof(iterationName));
    IEnumerable<FileInfo> resultFiles =
        EnumerateResultFiles(executionName, scenarioName, iterationName, cancellationToken);

    foreach (FileInfo resultFile in resultFiles)
    {
        cancellationToken.ThrowIfCancellationRequested();

        using FileStream stream = resultFile.OpenRead();

        ScenarioRunResult? result =
            await JsonSerializer.DeserializeAsync(
                stream,
                JsonUtilities.Default.ScenarioRunResultTypeInfo,
                cancellationToken).ConfigureAwait(false);

        yield return result is null
            ? throw new JsonException(
                string.Format(CultureInfo.CurrentCulture, DeserializationFailedMessage, resultFile.FullName))
            : result;
    }
}

