internal static void AddOpenAIResponseAttributes(
    string? serviceTier,
    string? systemFingerprint,
    ref string? capturedServiceTier,
    ref string? capturedSystemFingerprint)
{
    bool needsServiceTier = capturedServiceTier is null && !string.IsNullOrWhiteSpace(serviceTier);
    bool needsSystemFingerprint = capturedSystemFingerprint is null && !string.IsNullOrWhiteSpace(systemFingerprint);

    if (!needsServiceTier && !needsSystemFingerprint)
    {
        return;
    }

    if (GetCurrentChatActivity() is { } activity)
    {
        if (needsServiceTier)
        {
            capturedServiceTier = serviceTier;
            _ = activity.SetTag(OpenAIResponseServiceTierTag, serviceTier);
        }

        if (needsSystemFingerprint)
        {
            capturedSystemFingerprint = systemFingerprint;
            _ = activity.SetTag(OpenAIResponseSystemFingerprintTag, systemFingerprint);
        }
    }
}

private static ResponsesClientContinuationToken? CreateContinuationToken(
    string responseId,
    ResponseStatus? responseStatus,
    bool? isBackgroundModeEnabled,
    int? updateSequenceNumber = null)
{
    if (isBackgroundModeEnabled is not true)
    {
        return null;
    }

    // Returns a continuation token for in-progress or queued responses as they are not yet complete.
    // Also returns a continuation token if there is no status but there is a sequence number,
    // which can occur for certain streaming updates related to response content part updates: response.content_part.*,
    // response.output_text.*
    if ((responseStatus is ResponseStatus.InProgress or ResponseStatus.Queued) ||
        (responseStatus is null && updateSequenceNumber is not null))
    {
        return new ResponsesClientContinuationToken(responseId)
        {
            SequenceNumber = updateSequenceNumber,
        };
    }

    // For all other statuses: completed, failed, canceled, incomplete
    // return null to indicate the operation is finished allowing the caller
    // to stop and access the final result, failure details, reason for incompletion, etc.
    return null;
}

private static (bool hasApprovalRequiringFcc, int lastApprovalCheckedFCCIndex) CheckForApprovalRequiringFCC(
    List<FunctionCallContent>? functionCallContents,
    AITool[] approvalRequiredFunctions,
    bool hasApprovalRequiringFcc,
    int lastApprovalCheckedFCCIndex)
{
    // If we already found an approval requiring FCC, we can skip checking the rest.
    if (hasApprovalRequiringFcc)
    {
        Debug.Assert(functionCallContents is not null, "functionCallContents must not be null here, since we have already encountered approval requiring functionCallContents");
        return (true, functionCallContents!.Count);
    }

    if (functionCallContents is not null)
    {
        for (; lastApprovalCheckedFCCIndex < functionCallContents.Count; lastApprovalCheckedFCCIndex++)
        {
            var fcc = functionCallContents![lastApprovalCheckedFCCIndex];
            foreach (var arf in approvalRequiredFunctions)
            {
                if (arf.Name == fcc.Name)
                {
                    hasApprovalRequiringFcc = true;
                    break;
                }
            }
        }
    }

    return (hasApprovalRequiringFcc, lastApprovalCheckedFCCIndex);
}

