protected override async ValueTask<Outcome<TResult>> ExecuteCore<TResult, TState>(
    Func<ResilienceContext, TState, ValueTask<Outcome<TResult>>> callback,
    ResilienceContext context,
    TState state)
{
    HttpRequestMessage? request = context.GetRequestMessage();

    if (request is null)
    {
        Throw.InvalidOperationException("The HTTP request message was not found in the resilience context.");
    }

    if (_provider is null)
    {
        return await callback(context, state).ConfigureAwait(context.ContinueOnCapturedContext);
    }

    using var strategy = _provider();

    // if there are not routes we cannot continue
    if (!strategy.TryGetNextRoute(out var route))
    {
        Throw.InvalidOperationException("The routing strategy did not provide any route URL on the first attempt.");
    }

    context.Properties.Set(ResilienceKeys.RoutingStrategy, strategy);

    // for primary request, use retrieved route
    request.RequestUri = request.RequestUri!.ReplaceHost(route!);

    return await callback(context, state).ConfigureAwait(context.ContinueOnCapturedContext);
}

public async ValueTask<ServiceEndpoint> GetEndpointAsync(HttpRequestMessage request, CancellationToken cancellationToken)
    {
        ArgumentNullException.ThrowIfNull(request);
        if (request.RequestUri is null)
        {
            throw new InvalidOperationException("Cannot resolve an endpoint for a request which has no RequestUri");
        }

        EnsureCleanupTimerStarted();

        var key = request.RequestUri.GetLeftPart(UriPartial.Authority);
        while (true)
        {
            var resolver = _resolvers.GetOrAdd(
                key,
                static (name, self) => self.CreateResolver(name),
                this);

            var (valid, endpoint) = await resolver.TryGetEndpointAsync(request, cancellationToken).ConfigureAwait(false);
            if (valid)
            {
                if (endpoint is null)
                {
                    throw new InvalidOperationException($"Unable to resolve endpoint for service {resolver.ServiceName}");
                }

                return endpoint;
            }
            else
            {
                _resolvers.TryRemove(KeyValuePair.Create(resolver.ServiceName, resolver));
            }
        }
    }

public async Task<bool> InsertRow(MembershipEntry entry, TableVersion tableVersion)
        {
            LogTraceInsertRow(entry, tableVersion);

            //The "tableVersion" parameter should always exist when inserting a row as Init should
            //have been called and membership version created and read. This is an optimization to
            //not to go through all the way to database to fail a conditional check on etag (which does
            //exist for the sake of robustness) as mandated by Orleans membership protocol.
            //Likewise, no update can be done without membership entry.
            if (entry == null)
            {
                LogDebugInsertRowAbortedNullEntry();
                throw new ArgumentNullException(nameof(entry));
            }
            if (tableVersion is null)
            {
                LogDebugInsertRowAbortedNullTableVersion();
                throw new ArgumentNullException(nameof(tableVersion));
            }

            try
            {
                return await orleansQueries.InsertMembershipRowAsync(this.clusterId, entry, tableVersion.VersionEtag);
            }
            catch (Exception ex)
            {
                LogDebugInsertRowFailed(ex);
                throw;
            }
        }

public async Task MessagesDeliveredAsync(IList<IBatchContainer> messages)
    {
        // skip work if there are no messages to deliver
        if (messages.Count == 0)
        {
            return;
        }

        // get the identifiers for the messages to confirm
        var items = messages.Cast<AdoNetBatchContainer>().Select(x => new AdoNetStreamConfirmation(x.SequenceToken.SequenceNumber, x.Dequeued)).ToList();

        try
        {
            // execute the confirmation while pinning the task so shutdown can wait for it
            var task = queries.ConfirmStreamMessagesAsync(clusterOptions.ServiceId, providerId, queueId, items);
            _outstandingTask = task;

            try
            {
                await task;
            }
            catch (Exception ex)
            {
                LogConfirmationFailed(ex, clusterOptions.ClusterId, providerId, queueId, items);
                throw;
            }
        }
        finally
        {
            _outstandingTask = null;
        }
    }

public async ValueTask<bool> CreateIfNotExistsAsync(
    IReadOnlyDictionary<string, string>? metadata = null,
    CancellationToken cancellationToken = default)
{
    var startTimestamp = Stopwatch.GetTimestamp();
    var succeeded = false;
    var callerMetadata = CopyAndValidateCallerMetadata(metadata);
    try
    {
        var created = await CreateWalAsync(
            checkpointName: null,
            new AppendBlobRequestConditions { IfNoneMatch = ETag.All },
            cancellationToken,
            callerMetadata).ConfigureAwait(false);
        SetWal(created.Response.Value.ETag, created.ProviderState);
        succeeded = true;
        return true;
    }
    catch (RequestFailedException exception) when (exception.Status is 409 or 412)
    {
        succeeded = true;
        return false;
    }
    finally
    {
        AzureBlobJournalStorageInstruments.OnOperationCompleted(
            AzureBlobJournalStorageInstruments.OperationCreate,
            Stopwatch.GetElapsedTime(startTimestamp),
            bytes: 0,
            succeeded);
    }
}

private async ValueTask<WalState?> TryLoadWalStateAsync(
    BlobRequestConditions? conditions,
    CancellationToken cancellationToken,
    bool updateCache = true)
{
    Response<BlobProperties> walProperties;
    try
    {
        // Read only WAL properties and metadata; no journal bytes are needed to cache mutation state.
        walProperties = await _walClient.GetPropertiesAsync(conditions, cancellationToken).ConfigureAwait(false);
    }
    catch (RequestFailedException exception) when (exception.Status is 404)
    {
        // Missing WAL means there is no durable state to delete or mutate.
        if (updateCache)
        {
            SetWal(eTag: default, providerState: default);
        }

        return null;
    }

    var walDetails = walProperties.Value;
    var walState = CreateWalState(walDetails);

    // Cache the mutation precondition and compaction signal without replaying journal bytes.
    if (updateCache)
    {
        SetWal(walState.ETag, walState.ProviderState);
    }

    return walState;
}

protected virtual void AddCachePressureMonitors(
    IEventHubQueueCache cache,
    EventHubStreamCachePressureOptions providerOptions,
    ILogger cacheLogger)
{
    if (providerOptions.AveragingCachePressureMonitorFlowControlThreshold.HasValue)
    {
        var avgMonitor = new AveragingCachePressureMonitor(
            providerOptions.AveragingCachePressureMonitorFlowControlThreshold.Value, cacheLogger);
        cache.AddCachePressureMonitor(avgMonitor);
    }

    if (providerOptions.SlowConsumingMonitorPressureWindowSize.HasValue
        || providerOptions.SlowConsumingMonitorFlowControlThreshold.HasValue)
    {
        var slowConsumeMonitor = new SlowConsumingPressureMonitor(cacheLogger);
        if (providerOptions.SlowConsumingMonitorFlowControlThreshold.HasValue)
        {
            slowConsumeMonitor.FlowControlThreshold = providerOptions.SlowConsumingMonitorFlowControlThreshold.Value;
        }
        if (providerOptions.SlowConsumingMonitorPressureWindowSize.HasValue)
        {
            slowConsumeMonitor.PressureWindowSize = providerOptions.SlowConsumingMonitorPressureWindowSize.Value;
        }

        cache.AddCachePressureMonitor(slowConsumeMonitor);
    }
}
